const LOGO_EMAIL_HEADER_LIGHT_PNG_B64 = "";
const LOGO_EMAIL_HEADER_LIGHT_PNG = Uint8Array.from(atob(LOGO_EMAIL_HEADER_LIGHT_PNG_B64), c => c.charCodeAt(0));

const LOGO_EMAIL_HEADER_DARK_PNG_B64 = "";
const LOGO_EMAIL_HEADER_DARK_PNG = Uint8Array.from(atob(LOGO_EMAIL_HEADER_DARK_PNG_B64), c => c.charCodeAt(0));

const FAVICON_32_PNG_B64 = "";
const FAVICON_32_PNG = Uint8Array.from(atob(FAVICON_32_PNG_B64), c => c.charCodeAt(0));

const FAVICON_180_PNG_B64 = "";
const FAVICON_180_PNG = Uint8Array.from(atob(FAVICON_180_PNG_B64), c => c.charCodeAt(0));


const FROM = 'The Book of Your Life <hello@thebookofyour.life>';
const SITE = 'https://thebookofyour.life';
const LOGO_URL = `${SITE}/brand/logo-email-header.png`;
const MAX_BODY = 16 * 1024;        // 16KB per request — schedule with 25 entries fits easily
const ALLOWED_ORIGINS = ['https://thebookofyour.life', 'https://www.thebookofyour.life'];

// In-memory rate limit (best-effort within a single worker isolate)
// For real distributed limiting, use Cloudflare KV or Durable Objects — this catches casual abuse
const rateBucket = new Map();
function rateLimit(ip, key, limit, windowMs) {
  const now = Date.now();
  const k = `${ip}|${key}`;
  const arr = (rateBucket.get(k) || []).filter(t => now - t < windowMs);
  if (arr.length >= limit) return false;
  arr.push(now);
  rateBucket.set(k, arr);
  // Tiny GC: prune randomly so the map doesn't grow forever
  if (rateBucket.size > 5000 && Math.random() < 0.01) {
    for (const [mk, ts] of rateBucket) if (!ts.length || now - ts[ts.length - 1] > windowMs) rateBucket.delete(mk);
  }
  return true;
}

function escHtml(s) {
  if (s == null) return '';
  return String(s)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

async function safeJson(request) {
  const len = parseInt(request.headers.get('content-length') || '0', 10);
  if (len > MAX_BODY) throw new Error('Body too large');
  const text = await request.text();
  if (text.length > MAX_BODY) throw new Error('Body too large');
  try { return JSON.parse(text); } catch { throw new Error('Invalid JSON'); }
}

function buildCors(request) {
  const origin = request.headers.get('origin') || '';
  const allowed = ALLOWED_ORIGINS.includes(origin) ? origin : ALLOWED_ORIGINS[0];
  return {
    'Access-Control-Allow-Origin': allowed,
    'Access-Control-Allow-Methods': 'GET, POST, OPTIONS',
    'Access-Control-Allow-Headers': 'Content-Type',
    'Vary': 'Origin',
    'X-Content-Type-Options': 'nosniff',
    'X-Frame-Options': 'DENY',
    'Referrer-Policy': 'strict-origin-when-cross-origin',
  };
}

// Email header band — referenced by all email templates. PNG so Outlook + every client renders it.
// Light variant has a dark wordmark; that's what we want on white email backgrounds.
const EMAIL_HEADER = `
  <div style="text-align:center;padding:18px 0 4px">
    <a href="${SITE}" style="text-decoration:none;display:inline-block">
      <img src="${LOGO_URL}" alt="thebookofyour.life" width="280" height="56" style="display:block;border:0;outline:0;max-width:280px;height:auto;margin:0 auto"/>
    </a>
  </div>
`;
const EMAIL_FOOTER = `
  <div style="text-align:center;padding:24px 0 8px;border-top:1px solid #eee0c8;margin-top:32px">
    <p style="font-family:Georgia,serif;font-size:.78rem;color:#999;font-style:italic;margin:0">
      <a href="${SITE}" style="color:#c8a96e;text-decoration:none">thebookofyour.life</a> · A book that already knew you
    </p>
  </div>
`;

async function sendEmail(apiKey, { to, subject, html }) {
  if (!apiKey || !to) return;
  try {
    await fetch('https://api.resend.com/emails', {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${apiKey}`,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({ from: FROM, to, subject, html }),
    });
  } catch (e) {
    console.warn('Email failed:', e.message);
  }
}

async function notifySlack(webhookUrl, text) {
  if (!webhookUrl || !text) return;
  try {
    await fetch(webhookUrl, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ text }),
    });
  } catch (e) {
    console.warn('Slack notify failed:', e.message);
  }
}

export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname;
    const method = request.method;

    // CORS + security headers
    const cors = buildCors(request);
    const ip = request.headers.get('cf-connecting-ip') || 'anon';

    // Handle CORS preflight
    if (method === 'OPTIONS') {
      return new Response(null, { headers: cors });
    }

    // Block API calls from non-allowed origins (CSRF defense for browsers)
    if (path.startsWith('/api/') && method !== 'GET') {
      const origin = request.headers.get('origin') || '';
      if (origin && !ALLOWED_ORIGINS.includes(origin)) {
        return json({ error: 'Forbidden' }, 403, cors);
      }
    }

    // ── API ROUTES ──────────────────────────────────────

    // POST /api/gift — Sender creates a gift
    if (path === '/api/gift' && method === 'POST') {
      if (!rateLimit(ip, 'gift', 20, 60000)) return json({ error: 'Too many requests' }, 429, cors);
      try {
        const body = await safeJson(request);
        const senderName = sanitize(body.senderName, 80);
        const senderEmail = sanitize(body.senderEmail, 254);
        const recipientName = sanitize(body.recipientName, 80);
        const recipientEmail = sanitize(body.recipientEmail, 254);
        const personalNote = sanitize(body.personalNote, 500);
        const giftType = ['gift','self','birthday','referral'].includes(body.giftType) ? body.giftType : 'gift';
        if (!senderName || !recipientName) {
          return json({ error: 'senderName and recipientName required' }, 400, cors);
        }
        if (senderEmail && !isValidEmailServer(senderEmail)) {
          return json({ error: 'Invalid sender email' }, 400, cors);
        }
        if (recipientEmail && !isValidEmailServer(recipientEmail)) {
          return json({ error: 'Invalid recipient email' }, 400, cors);
        }
        const id = generateId();
        await env.DB.prepare(
          `INSERT INTO gifts (id, sender_name, sender_email, recipient_name, personal_note, gift_type) VALUES (?, ?, ?, ?, ?, ?)`
        ).bind(id, senderName, senderEmail, recipientName, personalNote, giftType).run();

        // Email recipient with their quiz link (all user input HTML-escaped)
        if (recipientEmail) {
          const quizLink = `https://thebookofyour.life/#gift/${encodeURIComponent(senderName)}/${id}`;
          const noteHtml = personalNote
            ? `<p style="font-style:italic;color:#555;border-left:3px solid #c8a96e;padding-left:14px;margin:20px 0">${escHtml(personalNote)}</p>`
            : '';
          await sendEmail(env.RESEND_API_KEY, {
            to: recipientEmail,
            subject: `${senderName.replace(/[\r\n]/g,'')} is sending you a book that knows you`,
            html: `
              <div style="font-family:Georgia,serif;max-width:560px;margin:0 auto;color:#1a1a1a">
                ${EMAIL_HEADER}
                <div style="padding:0 28px">
                  <p style="font-size:1.1rem">Dear ${escHtml(recipientName)},</p>
                  <p><strong>${escHtml(senderName)}</strong> wants to send you a book — but not just any book. A book matched to the philosophy closest to your life.</p>
                  ${noteHtml}
                  <p>Three minutes. Twenty-five honest questions. At the end, one of 31 philosophies and a book hand-picked for who you are. ${escHtml(senderName)} sees the philosophy and sends the book to your door. The book itself stays a surprise.</p>
                  <p style="margin:28px 0">
                    <a href="${quizLink}" style="background:#c8a96e;color:#fff;padding:12px 28px;border-radius:8px;text-decoration:none;font-size:1rem;font-weight:600">
                      Find your philosophy →
                    </a>
                  </p>
                  <p style="font-size:.85rem;color:#888">Or open this link: <a href="${quizLink}">${quizLink}</a></p>
                </div>
                ${EMAIL_FOOTER}
              </div>`,
          });
        }

        ctx.waitUntil(notifySlack(env.SLACK_WEBHOOK_URL,
          `:incoming_envelope: *${senderName}* sent the quiz to *${recipientName}*${recipientEmail ? ` (${recipientEmail})` : ''} _(${giftType})_`
        ));

        return json({ id, senderName, recipientName }, 200, cors);
      } catch (e) {
        return json({ error: e.message }, 500, cors);
      }
    }

    // GET /api/gift/:id — Sender checks results, recipient fetches personal note
    if (path.startsWith('/api/gift/') && method === 'GET') {
      if (!rateLimit(ip, 'gift-get', 60, 60000)) return json({ error: 'Too many requests' }, 429, cors);
      const rawId = path.replace('/api/gift/', '');
      const id = rawId.replace(/[^a-zA-Z0-9]/g, '').slice(0, 16);
      if (!id) return json({ error: 'Invalid id' }, 400, cors);
      try {
        const gift = await env.DB.prepare('SELECT * FROM gifts WHERE id = ?').bind(id).first();
        if (!gift) return json({ error: 'Gift not found' }, 404, cors);
        const result = await env.DB.prepare('SELECT * FROM results WHERE gift_id = ?').bind(id).first();
        return json({
          gift: {
            id: gift.id,
            senderName: gift.sender_name,
            recipientName: gift.recipient_name,
            personalNote: gift.personal_note || '',
            status: gift.status,
            createdAt: gift.created_at,
          },
          result: result ? {
            philosophyKey: result.philosophy_key,
            philosophyName: result.philosophy_name,
            runnerUp1: result.runner_up_1,
            runnerUp2: result.runner_up_2,
            bookTitle: result.book_title,
            bookAuthor: result.book_author,
            bookPrice: result.book_price,
            bookEmoji: result.book_emoji,
            amazonUrl: result.amazon_url,
            recipientName: result.recipient_name,
            recipientPhone: result.recipient_phone,
            recipientAddress: result.recipient_address,
          } : null
        }, 200, cors);
      } catch (e) {
        return json({ error: e.message }, 500, cors);
      }
    }

    // POST /api/result — Recipient submits quiz result + address
    if (path === '/api/result' && method === 'POST') {
      if (!rateLimit(ip, 'result', 10, 60000)) return json({ error: 'Too many requests' }, 429, cors);
      try {
        const body = await safeJson(request);
        const giftId = sanitize(body.giftId, 16).replace(/[^a-zA-Z0-9]/g, '');
        const philosophyKey = sanitize(body.philosophyKey, 30).replace(/[^a-z]/g, '');
        const philosophyName = sanitize(body.philosophyName, 80);
        const runnerUp1 = sanitize(body.runnerUp1, 80);
        const runnerUp2 = sanitize(body.runnerUp2, 80);
        const bookTitle = sanitize(body.bookTitle, 200);
        const bookAuthor = sanitize(body.bookAuthor, 200);
        const bookPrice = Math.max(0, Math.min(99999, parseInt(body.bookPrice, 10) || 0));
        const bookEmoji = sanitize(body.bookEmoji, 8);
        // Only allow https amazon URLs
        const rawAmz = sanitize(body.amazonUrl, 500);
        const amazonUrl = /^https:\/\/(www\.)?amazon\.(in|com|co\.uk)\//.test(rawAmz) ? rawAmz : '';
        const recipientName = sanitize(body.recipientName, 80);
        const recipientPhone = sanitize(body.recipientPhone, 20);
        const recipientAddress = sanitize(body.recipientAddress, 1000);

        if (!giftId || !philosophyKey || !bookTitle || !recipientAddress) {
          return json({ error: 'Missing required fields' }, 400, cors);
        }
        const gift = await env.DB.prepare(
          'SELECT id, status, sender_name, sender_email, gift_type FROM gifts WHERE id = ?'
        ).bind(giftId).first();
        if (!gift) return json({ error: 'Gift not found' }, 404, cors);
        if (gift.status === 'completed') return json({ error: 'Already completed' }, 409, cors);

        await env.DB.prepare(
          `INSERT INTO results (gift_id, philosophy_key, philosophy_name, runner_up_1, runner_up_2,
            book_title, book_author, book_price, book_emoji, amazon_url,
            recipient_name, recipient_phone, recipient_address)
           VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`
        ).bind(
          giftId, philosophyKey, philosophyName,
          runnerUp1, runnerUp2,
          bookTitle, bookAuthor, bookPrice, bookEmoji, amazonUrl,
          recipientName, recipientPhone, recipientAddress
        ).run();

        await env.DB.prepare(
          `UPDATE gifts SET status = 'completed', completed_at = datetime('now') WHERE id = ?`
        ).bind(giftId).run();

        // Email sender that recipient finished — skip self-mode (no sender to notify)
        if (gift.sender_email && gift.gift_type !== 'self') {
          const addrFormatted = escHtml(recipientAddress).replace(/\n/g, '<br>');
          const safeAmzUrl = amazonUrl || 'https://thebookofyour.life';
          await sendEmail(env.RESEND_API_KEY, {
            to: gift.sender_email,
            subject: `${(recipientName || gift.recipient_name).replace(/[\r\n]/g,'')} found their philosophy`,
            html: `
              <div style="font-family:Georgia,serif;max-width:560px;margin:0 auto;color:#1a1a1a">
                ${EMAIL_HEADER}
                <div style="padding:0 28px">
                  <p style="font-size:1.1rem">Dear ${escHtml(gift.sender_name)},</p>
                  <p><strong>${escHtml(recipientName || gift.recipient_name)}</strong> finished the quiz. Here's everything you need to send their book.</p>
                  <div style="background:#faf8f3;border:1px solid #e8e0cc;border-radius:10px;padding:20px;margin:20px 0">
                    <p style="margin:0 0 4px;font-size:.85rem;color:#888;font-style:italic">Their philosophy</p>
                    <p style="margin:0;font-size:1.2rem;font-weight:bold">${escHtml(philosophyName)}</p>
                    ${runnerUp1 ? `<p style="margin:6px 0 0;font-size:.85rem;color:#666;font-style:italic">And a touch of ${escHtml(runnerUp1)}</p>` : ''}
                  </div>
                  <div style="background:#faf8f3;border:1px solid #e8e0cc;border-radius:10px;padding:20px;margin:20px 0">
                    <p style="margin:0 0 4px;font-size:.85rem;color:#888;font-style:italic">The book to send</p>
                    <p style="margin:0;font-size:1.1rem;font-weight:bold">${escHtml(bookTitle)}</p>
                    <p style="margin:4px 0 0;font-size:.9rem;color:#555">by ${escHtml(bookAuthor)} &middot; ₹${bookPrice}</p>
                    <p style="margin:14px 0 0">
                      <a href="${safeAmzUrl}" style="background:#c8a96e;color:#fff;padding:11px 22px;border-radius:8px;text-decoration:none;font-size:.92rem;font-weight:600">Order on Amazon →</a>
                    </p>
                  </div>
                  <div style="background:#faf8f3;border:1px solid #e8e0cc;border-radius:10px;padding:20px;margin:20px 0">
                    <p style="margin:0 0 4px;font-size:.85rem;color:#888;font-style:italic">Deliver to</p>
                    <p style="margin:0;font-weight:bold">${escHtml(recipientName || gift.recipient_name)}</p>
                    ${recipientPhone ? `<p style="margin:2px 0;font-size:.9rem">${escHtml(recipientPhone)}</p>` : ''}
                    <p style="margin:4px 0 0;font-size:.9rem;color:#333">${addrFormatted}</p>
                  </div>
                </div>
                ${EMAIL_FOOTER}
              </div>`,
          });
        }

        ctx.waitUntil(notifySlack(env.SLACK_WEBHOOK_URL,
          `:white_check_mark: *${recipientName || gift.recipient_name}* finished the quiz · Philosophy: *${philosophyName}* · Book: ${bookEmoji} ${bookTitle}${bookAuthor ? ` by ${bookAuthor}` : ''}${gift.sender_name ? ` · gifted by ${gift.sender_name}` : ''}`
        ));

        return json({ success: true, giftId }, 200, cors);
      } catch (e) {
        return json({ error: e.message }, 500, cors);
      }
    }

    // POST /api/schedule — Schedule birthday gift reminders
    if (path === '/api/schedule' && method === 'POST') {
      if (!rateLimit(ip, 'schedule', 5, 60000)) return json({ error: 'Too many requests' }, 429, cors);
      try {
        const body = await safeJson(request);
        const senderName = sanitize(body.senderName, 80);
        const senderEmail = sanitize(body.senderEmail, 254);
        const rawEntries = Array.isArray(body.entries) ? body.entries : [];
        if (!senderName || !senderEmail || !rawEntries.length) {
          return json({ error: 'senderName, senderEmail and entries[] required' }, 400, cors);
        }
        if (!isValidEmailServer(senderEmail)) return json({ error: 'Invalid sender email' }, 400, cors);

        // Sanitize entries, dedupe within request, cap at 25
        // Accepts birthdayMD ("MM-DD") — no year asked or stored
        const MONTH_NAMES = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
        const DAYS_IN_MONTH = [31,29,31,30,31,30,31,31,30,31,30,31];
        const seen = new Set();
        const entries = [];
        for (const e of rawEntries.slice(0, 50)) {
          const name = sanitize(e && e.name, 80);
          const email = sanitize(e && e.email, 254);
          // Accept either new birthdayMD or legacy birthday (full date) — strip year if present
          let md = sanitize(e && (e.birthdayMD || e.birthday), 10);
          if (/^\d{4}-\d{2}-\d{2}$/.test(md)) md = md.slice(5);
          if (!name || !isValidEmailServer(email) || !/^\d{2}-\d{2}$/.test(md)) continue;
          const [mm, dd] = md.split('-');
          const mn = +mm, dn = +dd;
          if (mn < 1 || mn > 12 || dn < 1 || dn > DAYS_IN_MONTH[mn - 1]) continue;
          const key = `${email.toLowerCase()}|${md}`;
          if (seen.has(key)) continue;
          seen.add(key);
          entries.push({ name, email, md, label: `${MONTH_NAMES[mn-1]} ${dn}` });
          if (entries.length >= 25) break;
        }
        if (!entries.length) return json({ error: 'No valid entries (need name, email, month and day)' }, 400, cors);

        // Dedupe against existing rows for this sender/recipient/month-day
        const existing = await env.DB.prepare(
          `SELECT recipient_email, birthday_md FROM scheduled_gifts WHERE sender_email = ? AND status = 'active'`
        ).bind(senderEmail).all();
        const existingKeys = new Set((existing.results || []).map(r => `${r.recipient_email.toLowerCase()}|${r.birthday_md}`));
        const fresh = entries.filter(e => !existingKeys.has(`${e.email.toLowerCase()}|${e.md}`));
        if (!fresh.length) return json({ success: true, count: 0, duplicate: entries.length }, 200, cors);

        // birthday column is legacy — store synthetic 0000-MM-DD so it's clear no year was collected
        const stmt = env.DB.prepare(
          `INSERT INTO scheduled_gifts (sender_name, sender_email, recipient_name, recipient_email, birthday, birthday_md)
           VALUES (?, ?, ?, ?, ?, ?)`
        );
        await env.DB.batch(fresh.map(e => stmt.bind(senderName, senderEmail, e.name, e.email, `0000-${e.md}`, e.md)));

        // Confirmation email — escape user input. Only show month + day, never a year.
        if (env.RESEND_API_KEY) {
          const list = fresh.map(e => `<li><strong>${escHtml(e.name)}</strong> &middot; ${escHtml(e.label)}</li>`).join('');
          await sendEmail(env.RESEND_API_KEY, {
            to: senderEmail,
            subject: `${fresh.length} ${fresh.length > 1 ? 'birthdays' : 'birthday'} in motion`,
            html: `
              <div style="font-family:Georgia,serif;max-width:560px;margin:0 auto;color:#1a1a1a">
                ${EMAIL_HEADER}
                <div style="padding:0 28px">
                  <p style="font-size:1.1rem">Dear ${escHtml(senderName)},</p>
                  <p>It's done. Two weeks before each of these days, your friend will receive their quiz with your name on it. When they finish, you'll receive their philosophy, the book to send, and their address — right here, in this inbox.</p>
                  <ul style="padding-left:20px;line-height:1.9">${list}</ul>
                  <p style="font-size:.85rem;color:#888;margin-top:26px;font-style:italic">Add more anytime at <a href="${SITE}" style="color:#c8a96e">thebookofyour.life</a></p>
                </div>
                ${EMAIL_FOOTER}
              </div>`,
          });
        }

        const namesPreview = fresh.slice(0, 5).map(e => `${e.name} (${e.label})`).join(', ');
        const moreCount = fresh.length - 5;
        ctx.waitUntil(notifySlack(env.SLACK_WEBHOOK_URL,
          `:date: *${senderName}* scheduled *${fresh.length}* birthday reminder${fresh.length > 1 ? 's' : ''}: ${namesPreview}${moreCount > 0 ? ` +${moreCount} more` : ''}`
        ));

        return json({ success: true, count: fresh.length, duplicate: entries.length - fresh.length }, 200, cors);
      } catch (e) {
        return json({ error: e.message }, 500, cors);
      }
    }

    // GET /api/cron/process-birthdays — Manual trigger, requires admin token
    if (path === '/api/cron/process-birthdays' && method === 'GET') {
      const provided = url.searchParams.get('token') || '';
      if (!env.ADMIN_TOKEN || provided !== env.ADMIN_TOKEN) {
        return json({ error: 'Unauthorized' }, 401, cors);
      }
      try {
        const fired = await processBirthdayReminders(env);
        return json({ success: true, fired }, 200, cors);
      } catch (e) {
        return json({ error: e.message }, 500, cors);
      }
    }

    // POST /api/referral — Recipient submits referrals
    if (path === '/api/referral' && method === 'POST') {
      if (!rateLimit(ip, 'referral', 10, 60000)) return json({ error: 'Too many requests' }, 429, cors);
      try {
        const body = await safeJson(request);
        const giftId = sanitize(body.giftId, 16).replace(/[^a-zA-Z0-9]/g, '');
        const rawRefs = Array.isArray(body.referrals) ? body.referrals : [];
        if (!giftId || !rawRefs.length) return json({ error: 'giftId and referrals required' }, 400, cors);
        const refs = rawRefs.slice(0, 5).map(r => ({
          name: sanitize(r && r.name, 80),
          contact: sanitize(r && r.contact, 20).replace(/[^\d+]/g, '')
        })).filter(r => r.name && r.contact);
        if (!refs.length) return json({ error: 'No valid referrals' }, 400, cors);
        const stmt = env.DB.prepare('INSERT INTO referrals (source_gift_id, ref_name, ref_contact) VALUES (?, ?, ?)');
        await env.DB.batch(refs.map(r => stmt.bind(giftId, r.name, r.contact)));
        return json({ success: true, count: refs.length }, 200, cors);
      } catch (e) {
        return json({ error: e.message }, 500, cors);
      }
    }

    // ── SERVE STATIC BRAND ASSETS ───────────────────────
    const ASSETS = {
      '/brand/logo-mark.svg': { body: LOGO_MARK_SVG, type: 'image/svg+xml; charset=utf-8' },
      '/brand/logo-mark-light.svg': { body: LOGO_MARK_LIGHT_SVG, type: 'image/svg+xml; charset=utf-8' },
      '/brand/logo-email-header.png': { body: LOGO_EMAIL_HEADER_LIGHT_PNG, type: 'image/png' },
      '/brand/logo-email-header-light.png': { body: LOGO_EMAIL_HEADER_LIGHT_PNG, type: 'image/png' },
      '/brand/logo-email-header-dark.png': { body: LOGO_EMAIL_HEADER_DARK_PNG, type: 'image/png' },
      '/brand/favicon-32.png': { body: FAVICON_32_PNG, type: 'image/png' },
      '/brand/favicon-180.png': { body: FAVICON_180_PNG, type: 'image/png' },
      '/favicon.ico': { body: FAVICON_32_PNG, type: 'image/png' },
      '/apple-touch-icon.png': { body: FAVICON_180_PNG, type: 'image/png' },
      '/brand/og-card.jpg': { body: OG_CARD_JPG, type: 'image/jpeg' },
    };
    if (ASSETS[path]) {
      const a = ASSETS[path];
      return new Response(a.body, {
        headers: {
          'Content-Type': a.type,
          'Cache-Control': 'public, max-age=86400, s-maxage=604800',
          'X-Content-Type-Options': 'nosniff',
        },
      });
    }

    // ── SEO LANDING PAGES (one per philosophy) ──────────
    // /ikigai, /stoicism, /kintsugi, /hygge, /wabi-sabi etc.
    {
      const slug = path.replace(/^\//, '').replace(/\/$/, '');
      if (PHILOSOPHY_SLUGS.includes(slug)) {
        const html = renderPhilosophyPage(slug);
        if (html) {
          return new Response(html, {
            headers: {
              'Content-Type': 'text/html;charset=UTF-8',
              'Cache-Control': 'public, max-age=300, s-maxage=86400',
              'X-Content-Type-Options': 'nosniff',
              'X-Frame-Options': 'DENY',
              'Referrer-Policy': 'strict-origin-when-cross-origin',
              'Strict-Transport-Security': 'max-age=63072000; includeSubDomains; preload',
            },
          });
        }
      }
    }

    // ── SITEMAP + ROBOTS ────────────────────────────────
    if (path === '/sitemap.xml') {
      return new Response(renderSitemap(), {
        headers: {
          'Content-Type': 'application/xml;charset=UTF-8',
          'Cache-Control': 'public, max-age=3600, s-maxage=86400',
        },
      });
    }
    if (path === '/robots.txt') {
      return new Response(renderRobotsTxt(), {
        headers: {
          'Content-Type': 'text/plain;charset=UTF-8',
          'Cache-Control': 'public, max-age=3600, s-maxage=86400',
        },
      });
    }

    // ── SERVE STATIC HTML ───────────────────────────────
    return new Response(HTML, {
      headers: {
        'Content-Type': 'text/html;charset=UTF-8',
        'X-Content-Type-Options': 'nosniff',
        'X-Frame-Options': 'DENY',
        'Referrer-Policy': 'strict-origin-when-cross-origin',
        'Strict-Transport-Security': 'max-age=63072000; includeSubDomains; preload',
        // CSP allows inline styles/scripts (legacy single-file design), Hotjar, fonts, and same-origin API
        'Content-Security-Policy': [
          "default-src 'self'",
          "script-src 'self' 'unsafe-inline' https://static.hotjar.com https://script.hotjar.com",
          "style-src 'self' 'unsafe-inline' https://fonts.googleapis.com",
          "font-src 'self' https://fonts.gstatic.com",
          "img-src 'self' data: https://*.hotjar.com https://covers.openlibrary.org https://*.archive.org",
          "connect-src 'self' https://*.hotjar.com wss://*.hotjar.com",
          "frame-src https://vars.hotjar.com",
          "form-action 'self'",
          "base-uri 'self'",
          "object-src 'none'",
        ].join('; '),
      },
    });
  },

  // Cloudflare Cron Trigger — runs daily, scans for birthdays exactly 14 days away
  async scheduled(controller, env, ctx) {
    ctx.waitUntil(processBirthdayReminders(env));
  }
};

// ──────────────────────────────────────────────────────
//  BIRTHDAY REMINDER PROCESSOR
//  Runs daily. For each scheduled_gift whose birthday is exactly
//  14 days from today, create a gift record, email the recipient
//  the quiz link, and mark this year as fired.
// ──────────────────────────────────────────────────────
async function processBirthdayReminders(env) {
  const today = new Date();
  // Target = today + 14 days, then take MM-DD
  const target = new Date(today.getTime() + 14 * 86400000);
  const mm = String(target.getUTCMonth() + 1).padStart(2, '0');
  const dd = String(target.getUTCDate()).padStart(2, '0');
  const targetMD = `${mm}-${dd}`;
  const currentYear = today.getUTCFullYear();

  // Build list of MM-DDs to match. In non-leap years, treat Feb 28 target as also covering Feb 29 birthdays
  const targetMDs = [targetMD];
  const isLeap = (y) => (y % 4 === 0 && y % 100 !== 0) || y % 400 === 0;
  const targetYear = target.getUTCFullYear();
  if (targetMD === '02-28' && !isLeap(targetYear)) targetMDs.push('02-29');

  // Find all active scheduled gifts matching this MM-DD that haven't already fired this year
  const placeholders = targetMDs.map(() => '?').join(',');
  const { results: matches = [] } = await env.DB.prepare(
    `SELECT * FROM scheduled_gifts
     WHERE birthday_md IN (${placeholders})
       AND status = 'active'
       AND (last_fired_year IS NULL OR last_fired_year < ?)`
  ).bind(...targetMDs, currentYear).all();

  let fired = 0;
  for (const sg of matches) {
    try {
      const giftId = generateId();
      // Create the gift record so the existing /#gift/:sender/:gid flow works
      await env.DB.prepare(
        `INSERT INTO gifts (id, sender_name, sender_email, recipient_name, personal_note)
         VALUES (?, ?, ?, ?, ?)`
      ).bind(
        giftId,
        sg.sender_name,
        sg.sender_email,
        sg.recipient_name,
        `Scheduled for your birthday on ${sg.birthday}`
      ).run();

      // Mark scheduled gift as fired for this year
      await env.DB.prepare(
        `UPDATE scheduled_gifts SET last_fired_year = ?, gift_id = ? WHERE id = ?`
      ).bind(currentYear, giftId, sg.id).run();

      // Friendly month-day label like "Jun 22" — never includes a year on the friend's email
      const MONTH_NAMES = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
      const [bm, bd] = (sg.birthday_md || '').split('-');
      const bdayLabel = (bm && bd) ? `${MONTH_NAMES[parseInt(bm,10)-1]} ${parseInt(bd,10)}` : '';

      // Email the friend (no birthday date in subject or body — they probably know when their own birthday is)
      const quizLink = `https://thebookofyour.life/#gift/${encodeURIComponent(sg.sender_name)}/${giftId}`;
      await sendEmail(env.RESEND_API_KEY, {
        to: sg.recipient_email,
        subject: `${sg.sender_name.replace(/[\r\n]/g,'')} is sending you a birthday gift`,
        html: `
          <div style="font-family:Georgia,serif;max-width:560px;margin:0 auto;color:#1a1a1a">
            ${EMAIL_HEADER}
            <div style="padding:0 28px">
              <p style="font-size:1.1rem">Dear ${escHtml(sg.recipient_name)},</p>
              <p>Your birthday is coming up, and <strong>${escHtml(sg.sender_name)}</strong> would like to send you something thoughtful — a book matched to the philosophy closest to your life.</p>
              <p>Three minutes. Twenty-five honest questions. At the end, one of 31 philosophies and a book hand-picked for who you are. ${escHtml(sg.sender_name)} will see the philosophy and send the book to your door — the book itself stays a surprise.</p>
              <p style="margin:28px 0">
                <a href="${quizLink}" style="background:#c8a96e;color:#fff;padding:12px 28px;border-radius:8px;text-decoration:none;font-size:1rem;font-weight:600">
                  Find your philosophy →
                </a>
              </p>
              <p style="font-size:.85rem;color:#888">Or open this link: <a href="${quizLink}">${quizLink}</a></p>
            </div>
            ${EMAIL_FOOTER}
          </div>`,
      });

      // Notify the sender — warmer subject, month-day label only
      if (sg.sender_email) {
        await sendEmail(env.RESEND_API_KEY, {
          to: sg.sender_email,
          subject: `Heads up: ${sg.recipient_name.replace(/[\r\n]/g,'')}'s birthday gift is in motion`,
          html: `
            <div style="font-family:Georgia,serif;max-width:560px;margin:0 auto;color:#1a1a1a">
              ${EMAIL_HEADER}
              <div style="padding:0 28px">
                <p>Dear ${escHtml(sg.sender_name)},</p>
                <p><strong>${escHtml(sg.recipient_name)}'s</strong> birthday (${escHtml(bdayLabel)}) is two weeks away. Their quiz just landed in their inbox with your name on it.</p>
                <p>When they finish, you'll receive their philosophy, the book to send, and their address — right here, at this email. (Look for a note from <strong>hello@thebookofyour.life</strong>, just in case.)</p>
                <p style="margin:24px 0">
                  <a href="${SITE}/#results/${giftId}" style="background:#c8a96e;color:#fff;padding:10px 22px;border-radius:8px;text-decoration:none;font-size:.95rem">Track this gift</a>
                </p>
              </div>
              ${EMAIL_FOOTER}
            </div>`,
        });
      }

      await notifySlack(env.SLACK_WEBHOOK_URL,
        `:birthday: Auto-sent quiz to *${sg.recipient_name}* (${bdayLabel} birthday, scheduled by ${sg.sender_name})`
      );

      fired++;
    } catch (e) {
      console.warn('Birthday reminder failed for sched', sg.id, e.message);
    }
  }
  return fired;
}

function generateId() {
  // crypto-safe random ID instead of Math.random — guessability matters because gift_id grants address access
  const chars = 'abcdefghjkmnpqrstuvwxyz23456789';
  const buf = new Uint8Array(10);
  crypto.getRandomValues(buf);
  let id = '';
  for (let i = 0; i < 10; i++) id += chars[buf[i] % chars.length];
  return id;
}

// Trim, length-cap, strip control characters. Never null.
function sanitize(v, max = 200) {
  if (v == null) return '';
  let s = String(v).trim();
  // Strip ASCII control + zero-width chars that could hide attacks in display
  s = s.replace(/[\x00-\x1F\x7F​-‏‪-‮﻿]/g, '');
  if (s.length > max) s = s.slice(0, max);
  return s;
}

function isValidEmailServer(e) {
  return typeof e === 'string' && /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(e) && e.length <= 254;
}

function json(data, status = 200, extraHeaders = {}) {
  return new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json', ...extraHeaders }
  });
}
